/* BSW_CFG_TARGET = 23	RH850/U2A16 373Pin 使用コア4 */
#if	MCAL_PKG_U2A_TARGET == MCAL_PKG_U2A6_292PIN
#define		BSW_CFG_TARGET					(22U)
#elif MCAL_PKG_U2A_TARGET == MCAL_PKG_U2A16_373PIN
#define		BSW_CFG_TARGET					(23U)
#elif MCAL_PKG_U2A_TARGET == MCAL_PKG_U2A16_516PIN
#error "U2A16 516PIN is not supported"
#elif MCAL_PKG_U2A_TARGET == MCAL_PKG_U2A8_292PIN
#error "U2A8 292PIN is not supported"
#else
#error "Unknown MCU type"
#endif

