/************************************************************************************************/
/*	Service name		:	GetCoreId															*/
/*	Reentrancy			:	Concurrency safe													*/
/*	Parameters(in)		:	none																*/
/*	Return value		:	Core ID																*/
/*	Caveat				:	none																*/
/************************************************************************************************/
#define Bswlib_GetCoreId()	((U4)u4_g_GetCoreId())



/************************************************************************************************/
/*	Service name		:	Sync_Pipeline_1														*/
/*	Reentrancy			:	Concurrency safe													*/
/*	Parameters(in)		:	Register															*/
/*	Return value		:	none																*/
/*	Caveat				:	U1型のレジスタ以外で使用しないこと。								*/
/************************************************************************************************/
#define		Bswlib_Sync_Pipeline_1( t_u1Data )													\
	do																							\
	{																							\
		volatile	U1	t_u1BswLibDummy;														\
		t_u1BswLibDummy = (t_u1Data);															\
		__SYNCP();																				\
	}	while(0)

/************************************************************************************************/
/*	Service name		:	Sync_Pipeline_2														*/
/*	Reentrancy			:	Concurrency safe													*/
/*	Parameters(in)		:	Register															*/
/*	Return value		:	none																*/
/*	Caveat				:	U2型のレジスタ以外で使用しないこと。								*/
/************************************************************************************************/
#define		Bswlib_Sync_Pipeline_2( t_u2Data )													\
	do																							\
	{																							\
		volatile	U2	t_u2BswLibDummy;														\
		t_u2BswLibDummy = (t_u2Data);															\
		__SYNCP();																				\
	}	while(0)

/************************************************************************************************/
/*	Service name		:	Sync_Pipeline_4														*/
/*	Reentrancy			:	Concurrency safe													*/
/*	Parameters(in)		:	Register															*/
/*	Return value		:	none																*/
/*	Caveat				:	U4型のレジスタ以外で使用しないこと。								*/
/************************************************************************************************/
#define		Bswlib_Sync_Pipeline_4( t_u4Data )													\
	do																							\
	{																							\
		volatile	U4	t_u4BswLibDummy;														\
		t_u4BswLibDummy = (t_u4Data);															\
		__SYNCP();																				\
	}	while(0)




